(5, 14, NULL, 1, 0, 0, 'https://xn--fenster-tren24-osb.eu/mailto:info@fenster-türen24.eu', 'xn--fenster-tren24-osb.eu', 'info@fenster-türen24.eu', 'e-mail: info@fenster-türen24.eu', 'e-mail: <a href=\"mailto:info@fenster-türen24.eu\">info@fenster-türen24.eu</a>', 'e-mail: info@fenster-türen24.eu telefon: +49 173 6744073', 'e-mail: info@fenster-türen24.eu\r\ntelefon: +49 173 6744073', '2026-02-26 03:28:27', '2026-02-26 03:28:27');
INSERT INTO `wp_aioseo_notifications` (`id`, `slug`, `addon`, `title`, `content`, `type`, `level`, `notification_id`, `notification_name`, `start`, `end`, `button1_label`, `button1_action`, `button2_label`, `button2_action`, `dismissed`, `new`, `created`, `updated`) VALUES
(1, '699af3f502cad', NULL, 'Have you connected your site to Google Search Console?', 'AIOSEO can now verify whether your site is correctly verified with Google Search Console and that your sitemaps have been submitted correctly. Connect with Google Search Console now to ensure your content is being added to Google as soon as possible for increased rankings.', 'warning', '[\"all\"]', NULL, 'search-console-site-not-connected', '2026-02-22 12:17:57', NULL, 'Connect to Google Search Console', 'https://route#aioseo-settings&aioseo-scroll=google-search-console-settings&aioseo-highlight=google-search-console-settings:webmaster-tools?activetool=googleSearchConsole', NULL, NULL, 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(2, '699af3f531a14', NULL, 'Static sitemap files detected', 'AIOSEO has detected static sitemap files in the root folder of your WordPress installation.\n				As long as these files are present, AIOSEO is not able to dynamically generate your sitemap.', 'error', '[\"all\"]', NULL, 'sitemap-static-files', '2026-02-22 12:17:57', NULL, 'Delete Static Files', 'http://action#sitemap/delete-static-files', NULL, NULL, 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(3, '699af3f55456e', NULL, '🤖 4.8.8 is Here — Unleash the Power of AI on Your Website!', '<img src=\"data:image/webp;base64,\" alt=\"\" class=\"wp-image-1311\" style=\"object-fit:cover\"/>\n\n<p>Ready to create content, images, and boost your visibility faster than ever? With AIOSEO 4.8.8, you get cutting-edge AI features right inside WordPress:</p>\n\n<p>✅ Instantly generate blog posts, product copy, FAQs, and more with our new AI Assistant.</p>\n\n<p>✅ Create stunning, one-of-a-kind images with the Image Generator — no designer needed.</p>\n\n<p>✅ Take charge of how AI engines see your site using the new LLMS.txt Generator.</p>\n\n<p>Update to AIOSEO 4.8.8 now and supercharge your site with the future of SEO — powered by AI. 🚀</p>', 'success', '[\"4-x\",\"lite\"]', 1310, NULL, '2025-10-22 16:06:34', NULL, 'Learn More', 'https://aioseo.com/aioseo-4-8-8-release/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4.8.8-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4.8.8-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(4, '699af3f5551db', NULL, 'Introducing Site Audit in AIOSEO 4.8.6', '<p>Tired of guessing why your website isn’t ranking higher? Or frustrated by SEO tools that give you too much data but no clear answers?</p>\n\n<p>We’ve supercharged our SEO Analyzer to give you crystal-clear insights and action steps—right inside your WordPress dashboard!</p>\n\n<p>Now you can:</p>\n\n<p>✅ Scan your <strong>entire site</strong> for common SEO issues.</p>\n\n<p>✅ View issues <strong>page-by-page</strong> or <strong>by issue type</strong>.</p>\n\n<p>✅ <strong>Get instant tooltips</strong>, 1-click fixes, and quick keyword additions.</p>\n\n<p>✅ <strong>Track progress</strong> with satisfying visual checkmarks.</p>\n\n<p>Update to AIOSEO 4.8.6 today and take the guesswork out of SEO!</p>', 'success', '[\"4-x\",\"lite\"]', 1298, NULL, '2025-08-27 00:00:00', NULL, 'Learn More', 'https://aioseo.com/site-audit-announcement/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=486-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=486-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(5, '699af3f55558e', NULL, '[New] AI Content Generator: Supercharge Your Content Creation!', '<img src=\"data:image/webp;base64,\" alt=\"\" class=\"wp-image-1276\" style=\"object-fit:cover\"/>\n\n<p>Tired of the endless grind of crafting content, SEO titles, meta descriptions, social media posts, and FAQs?&nbsp;</p>\n\n<p>We get it! Creating high-quality, optimized content can be challenging and time-consuming. That\'s why we\'re thrilled to introduce AIOSEO\'s new <strong>AI Content Generator</strong>!</p>\n\n<p>Automatically generate content snippets like:</p>\n\n<p>✅ FAQs<br>✅ Key points<br>✅ Social media posts<br>✅ Email copy<br>✅ SEO titles and meta descriptions&nbsp;</p>\n\n<p>... and much more to come!</p>\n\n<p>Update to AIOSEO 4.8.4 now to unlock these powerful AI features and transform your content creation process! 🚀</p>', 'success', '[\"4-x\",\"lite\"]', 1270, NULL, '2025-07-09 13:36:07', NULL, 'Learn More', 'https://aioseo.com/new-ai-content-generator/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-484-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-484-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(6, '699af3f555b5d', NULL, '[New] Get Indexing Data Right Inside WordPress!', '<p>Worried Google\'s not seeing your amazing WordPress content? 🤔&nbsp;</p>\n\n<p>AIOSEO 4.8.2 introduces the <strong>Index Status Report</strong>, giving you crystal-clear visibility into what <strong>Google\'s indexing</strong> (and what it\'s missing!). <strong>Uncover hidden indexing issues</strong>, see post-level details, and track your rich results—all within your familiar WordPress dashboard.&nbsp;</p>\n\n<p>Stop losing traffic and ensure your hard work gets seen.&nbsp;</p>\n\n<p>Update to AIOSEO 4.8.2 today and take control of your website’s visibility! 🚀</p>', 'success', '[\"4-x\",\"lite\"]', 1249, NULL, '2025-05-22 15:19:11', NULL, 'Learn More', 'https://aioseo.com/introducing-index-status-report/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-482-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-482-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(7, '699af3f555f24', NULL, '[New] Supercharged Crawl Cleanup and Query Arg Monitoring! 🚀', '<p>Is your WordPress site slowing down? Or are AI bots scraping your content? 🧐</p>\n\n<p><strong>AIOSEO 4.8.0 puts you in control with</strong>:<br>🧹 <strong>Supercharged Crawl Cleanup</strong> – Stop search engines from indexing unnecessary URLs.<br>📊 <strong>Advanced Query Monitoring</strong> – Optimize UTM parameters automatically.<br>🛡️ <strong>Bot Control</strong> – Block unauthorized AI crawlers.<br>🔍 <strong>Internal Search Optimization</strong> – Prevent spam &amp; boost performance.<br><br>🔥 Keep your site fast, secure, and SEO-friendly. Update now! 🚀</p>', 'success', '[\"4-x\",\"lite\"]', 1222, NULL, '2025-03-11 00:00:00', NULL, 'Learn More', 'https://aioseo.com/introducing-aioseo-4-8-0-advanced-crawl-features/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=480-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=480-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(8, '699af3f5562ea', NULL, '[New] Smarter Keyword Rank Tracking &amp; WooCommerce SEO Made Easy!🤩', '<p>We just released AIOSEO 4.7.8 and it’s loaded with some exciting updates!</p>\n\n<p>The top ones include:</p>\n\n<p>👉🏼 <strong>Smarter Keyword Rank Tracker</strong>: Our Keyword Rank Tracker just got some massive upgrades you don’t want to miss. Now you can get related keywords, import keywords from GSC and more.</p>\n\n<p>👉🏼 <strong>Support for WooCommerce Product Attributes</strong>: Setting product attributes in WordPress just got way easier. Plus, you can also export product attributes! </p>\n\n<p>Update to AIOSEO 4.7.8 now and take your SEO to another level.</p>', 'success', '[\"4-x\",\"lite\"]', 1213, NULL, '2025-01-28 00:00:00', NULL, 'Learn More', 'https://aioseo.com/smarter-keyword-rank-tracking-woocommerce-seo-made-easy/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=478-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=478-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(9, '699af3f55666b', NULL, 'BuddyPress, Web Stories, and Enhanced Author SEO — An All in One Update! 🚀!', '<p>We just released AIOSEO 4.7.6 and it’s loaded with some exciting updates!</p>\n\n<p>The top ones include:<br><br>🤩 <strong>BuddyPress Integration:</strong> Fully optimize SEO settings for BuddyPress content types, including user profiles, activity streams, and more.<br>🤩 <strong>Google Web Stories Integration:</strong> Take full control of your SEO settings for Web Stories, resulting in more eyeballs on your content.<br>🤩 <strong>Author SEO Improvements:</strong> Effortlessly showcase Google\'s E-E-A-T guidelines and boost your site\'s credibility.</p>\n\n<p>Update to AIOSEO 4.7.6 now and take your SEO to another level 💪🏼</p>', 'success', '[\"4-x\",\"lite\"]', 1192, NULL, '2024-12-12 00:00:00', NULL, 'Learn More', 'https://aioseo.com/new-aioseo-4-7-6-buddypress-web-stories-integration-author-seo-improvements?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=476-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=476-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(10, '699af3f556a84', NULL, '[New] Meet Your New Writing Assistant ✍️!', '<p>🚀 New Feature Alert!&nbsp;</p>\n\n<p>We\'re thrilled to announce the release of our groundbreaking feature —<strong>Writing Assistant</strong>, powered by AIOSEO and SEOBoost 🥳</p>\n\n<p><strong>The Writing Assistant is your new personal guide to crafting SEO-friendly content right inside WordPress! 📝 </strong></p>\n\n<p>No more guesswork—just optimized content that ranks.</p>\n\n<p>Update to AIOSEO 4.7.4 now and unlock this revolutionary superpower!</p>', 'success', '[\"4-x\",\"lite\"]', 1166, NULL, '2024-11-05 00:00:00', NULL, 'Learn More', 'https://aioseo.com/new-revolutionize-your-content-creation-with-aioseos-writing-assistant/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=474-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=474-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(11, '699af3f556e12', NULL, '[New] SEO Email Reports and Bulk CSV Imports/Exports to Enhance SEO Management', '<p>🚀 New Feature Alert! </p>\n\n<p>AIOSEO 4.7.2 just dropped with two killer features - </p>\n\n<ol class=\"wp-block-list\">\n<li><strong>SEO Email Reports</strong><br>👋 Say goodbye to manual SEO performance tracking and hello to laser-focused insights delivered straight to your inbox! 📥</li>\n\n<li><strong>Bulk CSV Import/Export</strong><br>⚡️The new Bulk CSV tool lets you manage settings across your entire site in a snap. 🔄 Export, edit, and import easily – it\'s like having an SEO superpower at your fingertips! 💪</li>\n</ol>\n\n<p>Update to AIOSEO 4.7.2 now and unlock these game-changing features!</p>\n\n<p></p>', 'success', '[\"4-x\",\"lite\"]', 1156, NULL, '2024-10-08 00:00:00', NULL, 'Learn More', 'https://aioseo.com/new-seo-email-reports-and-bulk-csv-imports/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=472-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=472-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(12, '699af3f55719e', NULL, '[New] Keyword Rank Tracker: Track Your SEO Performance with Ease ?', '<p>Drumroll, please! AIOSEO 4.7.0 has arrived with a super-awaited feature: the <strong>Keyword Rank Tracker</strong> ?</p>\n\n<p>Now, you can finally track your keyword performance with ease, right from your WordPress dashboard. No more guessing games!</p>\n\n<p>Key features:</p>\n\n<p>✅ Track up to 100 keywords<br>✅ Group keywords for better organization<br>✅ Seamless integration with post-meta box</p>\n\n<p>Get ready to dominate SERPs!</p>\n\n<p><strong>Update to AIOSEO 4.7.0 now and unlock this SEO powerhouse.</strong></p>', 'success', '[\"4-x\",\"lite\"]', 1148, NULL, '2024-09-10 00:00:00', NULL, 'Learn More', 'https://aioseo.com/new-track-your-keywords-effortlessly-in-wordpress-with-aioseo-4-7-0/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-470-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/lite-upgrade/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=aioseo-470-v4-x-lite', 0, 0, '2026-02-22 12:17:57', '2026-02-22 12:17:57'),
(13, '699fbca0cb575', NULL, 'Meet Your New SEO Checklist in AIOSEO 4.9.4!', '<p>Maximize your site\'s potential with our latest update:</p>\n\n<p><strong>✅ SEO Checklist: </strong>A new interactive guide to help you complete your setup and explore advanced features. Finish the tasks to see the confetti fly!</p>\n\n<p><strong>🤖 AI Suite:</strong> We’ve renamed AI Insights to AI Suite and moved all AI Content Settings there to centralize your tools.</p>\n\n<p><strong>⚙️ License Tab:</strong> The General Settings tab is now the License tab, featuring a clearer UI and easy access to AI Credit connections.</p>\n\n<p>Update to AIOSEO 4.9.4 and follow the roadmap to a fully optimized site! 🚀</p>', 'success', '[\"4-x\",\"lite\"]', 1397, NULL, '2026-02-24 00:00:00', NULL, 'Learn More', 'https://aioseo.com/aioseo-4-9-4-release/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4-9-4-announcement-v4-x-lite', 'Get AIOSEO Pro', 'https://aioseo.com/pricing/?utm_source=WordPress&utm_medium=plugin-notification&utm_campaign=4-9-4-announcement-v4-x-lite', 0, 0, '2026-02-26 03:23:12', '2026-02-26 03:23:12');
