(51, 16, '_form', '<label> Vorname (erfordelich)\n    [text* your-name] </label>\n\n<label> Email Adresse (erfordelich)\n    [email* your-email] </label>\n\n<label> Thema\n    [text your-subject] </label>\n\n<label> Nachrichteninhalt\n    [textarea your-message] </label>\n\n[turnstile]\n\n[submit \"Absenden\"]'),
(52, 16, '_mail', 'a:9:{s:6:\"active\";b:1;s:7:\"subject\";s:26:\"Fenster - \"[your-subject]\"\";s:6:\"sender\";s:49:\"[your-name] <wordpress@xn--fenster-tren24-osb.eu>\";s:9:\"recipient\";s:24:\"info@fenster-tueren24.eu\";s:4:\"body\";s:215:\"Nadawca: [your-name] <[your-email]>\nTemat: [your-subject]\n\nTreść wiadomości:\n[your-message]\n\n-- \nTa wiadomość została wysłana przez formularz kontaktowy na stronie Fenster (https://xn--fenster-tren24-osb.eu).\";s:18:\"additional_headers\";s:22:\"Reply-To: [your-email]\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:0;s:13:\"exclude_blank\";b:0;}'),
(53, 16, '_mail_2', 'a:9:{s:6:\"active\";b:0;s:7:\"subject\";s:26:\"Fenster - \"[your-subject]\"\";s:6:\"sender\";s:45:\"Fenster <wordpress@xn--fenster-tren24-osb.eu>\";s:9:\"recipient\";s:12:\"[your-email]\";s:4:\"body\";s:156:\"Treść wiadomości:\n[your-message]\n\n-- \nTa wiadomość została wysłana przez formularz kontaktowy na stronie Fenster (https://xn--fenster-tren24-osb.eu).\";s:18:\"additional_headers\";s:23:\"Reply-To: darekl@gmx.de\";s:11:\"attachments\";s:0:\"\";s:8:\"use_html\";b:0;s:13:\"exclude_blank\";b:0;}'),
(54, 16, '_messages', 'a:22:{s:12:\"mail_sent_ok\";s:53:\"Ihre Nachricht wurde erfolgreich übermittelt. Danke.\";s:12:\"mail_sent_ng\";s:87:\"Die Nachricht konnte nicht gesendet werden. Bitte versuchen Sie es später noch einmal.\";s:16:\"validation_error\";s:109:\"Mindestens ein Feld bzw. Zeile wurde falsch ausgefüllt. Überprüfen Sie den Inhalt und versuchen es erneut.\";s:4:\"spam\";s:80:\"Wystąpił problem z wysłaniem twojej wiadomości. Spróbuj ponownie później.\";s:12:\"accept_terms\";s:72:\"Musisz wyrazić zgodę na powyższe zapisy, aby móc wysłać formularz.\";s:16:\"invalid_required\";s:12:\"Pflichtfeld.\";s:16:\"invalid_too_long\";s:39:\"Zawartość tego pola jest zbyt długa.\";s:17:\"invalid_too_short\";s:40:\"Zawartość tego pola jest zbyt krótka.\";s:13:\"upload_failed\";s:51:\"Podczas wgrywania pliku wystąpił nieznany błąd.\";s:24:\"upload_file_type_invalid\";s:39:\"Nie możesz wgrywać plików tego typu.\";s:21:\"upload_file_too_large\";s:25:\"Ten plik jest zbyt duży.\";s:23:\"upload_failed_php_error\";s:42:\"Wystąpił błąd podczas wgrywania pliku.\";s:12:\"invalid_date\";s:29:\"Format daty jest niepoprawny.\";s:14:\"date_too_early\";s:49:\"Data jest wcześniejsza, niż pierwsza dozwolona.\";s:13:\"date_too_late\";s:48:\"Data jest późniejsza, niż ostatnia dozwolona.\";s:14:\"invalid_number\";s:31:\"Format liczby jest niepoprawny.\";s:16:\"number_too_small\";s:52:\"Ta liczba jest mniejsza, niż minimalna dopuszczana.\";s:16:\"number_too_large\";s:54:\"Ta liczba jest większa, niż maksymalna dopuszczalna.\";s:23:\"quiz_answer_not_correct\";s:40:\"Odpowiedź w quizie jest nieprawidłowa.\";s:13:\"invalid_email\";s:37:\"Die E-mail Adresse ist nicht korrekt.\";s:11:\"invalid_url\";s:42:\"Wprowadzony adres URL jest nieprawidłowy.\";s:11:\"invalid_tel\";s:47:\"Wprowadzony numer telefonu jest nieprawidłowy.\";}'),
