(10, 1, '2018-06-20 23:58:09', '2018-06-20 21:58:09', 'Planen Sie mit mir zusammen Ihren Umbau. Ich übernehme alle anfallenden Montage- und Demontagearbeiten für diese Arbeiten.\r\n\r\nIch kümmere mich wenn gewünscht auch für den Abtransport des anfallenden Bauschutts und endsorge ihn auf eine Deponie.\r\n\r\n<a href=\"https://xn--fenster-tren24-osb.eu/wp-content/uploads/2018/06/montage.jpg\"><img class=\"alignleft size-full wp-image-33\" src=\"https://xn--fenster-tren24-osb.eu/wp-content/uploads/2018/06/montage.jpg\" alt=\"\" width=\"796\" height=\"453\" /></a>', 'Montage und Demontage', '', 'publish', 'closed', 'closed', '', 'montage-demontage', '', '', '2018-10-12 11:07:30', '2018-10-12 09:07:30', '', 6, 'http://xn--fenster-tren24-osb.eu/?page_id=10', 3, 'page', '', 0),
(11, 1, '2018-06-20 23:58:33', '2018-06-20 21:58:33', '<strong>Bei bestellten Produkten:</strong>\r\n- kostenlose Lieferung im Umkreis bis 100 km.;\r\n- Lieferung ca. 2- 4 Wochen nach Bestellung;\r\n- 50% Anzahlung bei Bestellung;\r\n- weitere 30% bei Auslieferung;\r\n- restlicher 20% nach abgeschossenen Auftrag.\r\n\r\n<a href=\"https://xn--fenster-tren24-osb.eu/wp-content/uploads/2018/06/lieferung2.jpg\"><img src=\"https://xn--fenster-tren24-osb.eu/wp-content/uploads/2018/06/lieferung2.jpg\" alt=\"\" width=\"800\" height=\"450\" class=\"alignleft size-full wp-image-34\" /></a>', 'Lieferung', '', 'publish', 'closed', 'closed', '', 'lieferung', '', '', '2018-06-21 01:12:09', '2018-06-20 23:12:09', '', 6, 'http://xn--fenster-tren24-osb.eu/?page_id=11', 4, 'page', '', 0),
